export type Offset = number;

export const SIZE_PREFIX_LENGTH = 4;

export enum Encoding {
  UTF8_BYTES = 1,
}

const UTF8_DECODER = new TextDecoder();

export class ByteBuffer {
  private readonly dataView: DataView;
  private readonly rawBytes: Uint8Array;
  private bbPosition = 0;

  constructor(bytes: Uint8Array) {
    this.rawBytes = bytes;
    this.dataView = new DataView(bytes.buffer, bytes.byteOffset, bytes.byteLength);
  }

  bytes(): Uint8Array {
    return this.rawBytes;
  }

  position(): number {
    return this.bbPosition;
  }

  setPosition(position: number): void {
    this.bbPosition = position;
  }

  readInt32(offset: number): number {
    return this.dataView.getInt32(offset, true);
  }

  readUint8(offset: number): number {
    return this.dataView.getUint8(offset);
  }

  readUint32(offset: number): number {
    return this.dataView.getUint32(offset, true);
  }

  readUint64(offset: number): bigint {
    return this.dataView.getBigUint64(offset, true);
  }

  readFloat32(offset: number): number {
    return this.dataView.getFloat32(offset, true);
  }

  __offset(tableOffset: number, vtableOffset: number): number {
    const vtable = tableOffset - this.readInt32(tableOffset);
    const vtableLength = this.readUint16(vtable);
    return vtableOffset < vtableLength ? this.readUint16(vtable + vtableOffset) : 0;
  }

  __indirect(offset: number): number {
    return offset + this.readInt32(offset);
  }

  __vector(offset: number): number {
    const vectorOffset = offset + this.readInt32(offset);
    return vectorOffset + SIZE_PREFIX_LENGTH;
  }

  __vector_len(offset: number): number {
    const vectorOffset = offset + this.readInt32(offset);
    return this.readInt32(vectorOffset);
  }

  __string(offset: number, encoding?: Encoding): string | Uint8Array {
    const stringOffset = offset + this.readInt32(offset);
    const stringLength = this.readInt32(stringOffset);
    const stringBytes = this.rawBytes.subarray(
      stringOffset + SIZE_PREFIX_LENGTH,
      stringOffset + SIZE_PREFIX_LENGTH + stringLength,
    );
    if (encoding === Encoding.UTF8_BYTES) {
      return stringBytes;
    }
    return UTF8_DECODER.decode(stringBytes);
  }

  __has_identifier(identifier: string): boolean {
    if (identifier.length !== SIZE_PREFIX_LENGTH) {
      return false;
    }
    const identifierOffset = this.bbPosition + SIZE_PREFIX_LENGTH;
    if (identifierOffset + SIZE_PREFIX_LENGTH > this.rawBytes.length) {
      return false;
    }
    for (let index = 0; index < identifier.length; index += 1) {
      if (this.rawBytes[identifierOffset + index] !== identifier.charCodeAt(index)) {
        return false;
      }
    }
    return true;
  }

  private readUint16(offset: number): number {
    return this.dataView.getUint16(offset, true);
  }
}

export class Builder {
  private notImplemented(method: string): never {
    throw new Error(`flatbuffers.Builder.${method} is not implemented in this local runtime yet.`);
  }

  startObject(_numFields: number): void {
    this.notImplemented("startObject");
  }

  addFieldOffset(_voffset: number, _value: Offset, _defaultValue: Offset): void {
    this.notImplemented("addFieldOffset");
  }

  addFieldInt64(_voffset: number, _value: bigint, _defaultValue: bigint): void {
    this.notImplemented("addFieldInt64");
  }

  addFieldInt32(_voffset: number, _value: number, _defaultValue: number): void {
    this.notImplemented("addFieldInt32");
  }

  endObject(): Offset {
    return this.notImplemented("endObject");
  }

  finish(_offset: Offset, _fileIdentifier?: string, _sizePrefixed?: boolean): void {
    this.notImplemented("finish");
  }

  startVector(_elemSize: number, _numElems: number, _alignment: number): void {
    this.notImplemented("startVector");
  }

  addOffset(_offset: Offset): void {
    this.notImplemented("addOffset");
  }

  addFloat32(_value: number): void {
    this.notImplemented("addFloat32");
  }

  addInt8(_value: number): void {
    this.notImplemented("addInt8");
  }

  endVector(): Offset {
    return this.notImplemented("endVector");
  }
}
